impl From<u16> for Ruby {
    #[inline(always)]
    fn from(x: u16) -> Self {
        num::FromPrimitive::from_u16(x).unwrap_or(Self::Error)
    }
}

// Ruby == u16
impl PartialEq<u16> for Ruby {
    #[inline(always)]
    fn eq(&self, x: &u16) -> bool {
        *self == Into::<Self>::into(*x)
    }
}

// u16 == Ruby
impl PartialEq<Ruby> for u16 {
    #[inline(always)]
    fn eq(&self, x: &Ruby) -> bool {
        *x == *self
    }
}
